import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import {
  Home, ShoppingBag, Package, MapPin, Settings, User, X,
  Sparkles, ChevronDown, Shield, Globe, CreditCard, LayoutGrid,
  Heart, Bell, HelpCircle
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useTranslation } from 'react-i18next';

import './Sidebar.css';

/* ── Logo ── */
function QualityProductsLogo({ size = 32 }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 64 64"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className="brand-logo"
    >
      <rect width="64" height="64" rx="14" fill="url(#logoGradient)" />
      <text
        x="32" y="43"
        textAnchor="middle"
        fontFamily="Arial, sans-serif"
        fontWeight="bold"
        fontSize="28"
        fill="#ffffff"
        letterSpacing="1"
      >QP</text>
      <defs>
        <linearGradient id="logoGradient" x1="0" y1="0" x2="64" y2="64">
          <stop offset="0%" stopColor="#6366f1" />
          <stop offset="100%" stopColor="#8b5cf6" />
        </linearGradient>
      </defs>
    </svg>
  );
}

/* ── Collapsible nav group ── */
function NavGroup({ label, children, defaultOpen = true }) {
  const [open, setOpen] = useState(defaultOpen);

  return (
    <div className={`sidebar-group ${open ? 'sidebar-group--open' : ''}`}>
      <button className="sidebar-group-label" onClick={() => setOpen(!open)}>
        <span>{label}</span>
        <ChevronDown size={14} className="sidebar-group-chevron" />
      </button>
      <div className="sidebar-group-items">{children}</div>
    </div>
  );
}

export default function Sidebar({ isOpen, onClose }) {
  const { t } = useTranslation();
  const { user, isAuthenticated } = useAuth();

  const mainNav = [
    { path: '/',         icon: Home,         label: t('nav.home') },
    { path: '/products', icon: LayoutGrid,   label: t('nav.products') },
    { path: '/wishlist', icon: Heart,        label: t('nav.wishlist') },
  ];

  const ordersNav = [
    { path: '/orders',   icon: Package,  label: t('nav.orders') },
    { path: '/tracking', icon: MapPin,   label: t('nav.tracking') },
    { path: '/payments', icon: CreditCard, label: t('nav.payments', 'Payments') },
  ];

  const accountNav = [
    { path: '/account',  icon: User,     label: t('nav.account') },
    { path: '/settings', icon: Settings, label: t('nav.settings') },
    { path: '/privacy',  icon: Shield,   label: t('nav.privacy', 'Privacy') },
  ];

  const renderLink = ({ path, icon: Icon, label, badge }) => (
    <NavLink
      key={path}
      to={path}
      end={path === '/'}
      className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}
      onClick={onClose}
    >
      <span className="sidebar-link-icon"><Icon size={20} /></span>
      <span className="sidebar-link-text">{label}</span>
      {badge && <span className="sidebar-badge">{badge}</span>}
    </NavLink>
  );

  return (
    <>
      {isOpen && <div className="sidebar-overlay" onClick={onClose} />}

      <aside className={`sidebar ${isOpen ? 'open' : ''}`}>
        {/* ── Header ── */}
        <div className="sidebar-header">
          <span className="brand-name">
            <QualityProductsLogo size={30} />
            <span className="brand-text">
              Quality<span className="brand-accent">Products</span>
            </span>
          </span>
          <button className="sidebar-close" onClick={onClose} aria-label="Close menu">
            <X size={20} />
          </button>
        </div>

        {/* ── User Card (when authenticated) ── */}
        {isAuthenticated && user && (
          <div className="sidebar-user-card">
            <div className="sidebar-user-avatar">
              {user.fullName?.[0] || 'U'}
            </div>
            <div className="sidebar-user-info">
              <p className="sidebar-user-name">{user.fullName || 'User'}</p>
              <p className="sidebar-user-email">{user.email}</p>
            </div>
          </div>
        )}

        {/* ── Navigation ── */}
        <nav className="sidebar-nav">
          <NavGroup label={t('nav.menu', 'Menu')} defaultOpen>
            {mainNav.map(renderLink)}
          </NavGroup>

          <NavGroup label={t('nav.orders', 'Orders')} defaultOpen>
            {ordersNav.map(renderLink)}
          </NavGroup>

          <NavGroup label={t('nav.account', 'Account')} defaultOpen>
            {accountNav.map(renderLink)}
          </NavGroup>
        </nav>

        {/* ── Help link ── */}
        <div className="sidebar-help">
          <NavLink to="/help" className="sidebar-help-link" onClick={onClose}>
            <HelpCircle size={18} />
            <span>{t('nav.help', 'Help & Support')}</span>
          </NavLink>
        </div>

        {/* ── Footer ── */}
        <div className="sidebar-footer">
          <div className="ai-badge">
            <Sparkles size={14} />
            <span>Powered by QualityProducts</span>
          </div>
        </div>
      </aside>
    </>
  );
}
